import{_ as s}from"./chunks/rviz.C5CaD62O.js";import{_ as a,c as t,o as l,a4 as e}from"./chunks/framework.BxjRYGQi.js";const g=JSON.parse('{"title":"在RViz中显示捷勃特机器人模型","description":"","frontmatter":{},"headers":[],"relativePath":"zh/02-quick-start/01-Visualize_URDF.md","filePath":"zh/02-quick-start/01-Visualize_URDF.md"}'),h={name:"zh/02-quick-start/01-Visualize_URDF.md"};function n(p,i,r,k,d,o){return l(),t("div",{"data-pagefind-body":!0},i[0]||(i[0]=[e('<h1 id="在rviz中显示捷勃特机器人模型" tabindex="-1">在 RViz 中显示捷勃特机器人模型 <a class="header-anchor" href="#在rviz中显示捷勃特机器人模型" aria-label="Permalink to “在RViz中显示捷勃特机器人模型”">​</a></h1><p>本章节介绍如何使用 ROS 2 在 RViz 中显示捷勃特机器人模型，并通过 GUI 工具进行交互。RViz（ROS 可视化）是 ROS 生态中用于实时可视化机器人模型、传感器数据和环境信息的工具。它可以：</p><ul><li>加载并显示 URDF 格式的机器人模型</li><li>可视化激光雷达点云、深度相机点云等 2D/3D 传感器数据</li><li>显示机器人关节状态、轨迹规划结果和 TF 坐标变换</li><li>通过交互标记和 GUI 插件，实现对机器人姿态和目标的在线调整</li></ul><p>显示效果如下：</p><h2 id="rviz" tabindex="-1"><img src="'+s+`" alt="RViz"> <a class="header-anchor" href="#rviz" aria-label="Permalink to “”">​</a></h2><p>要查看上海捷勃特机器人的 URDF 模型，请执行以下命令启动 RViz：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {您的工作目录}</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install/setup.bash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_description</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> display_robot.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:={机器人型号}</span></span></code></pre></div><p>例如，如果您想查看 C5A 型号的机器人：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {您的工作目录}</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install/setup.bash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_description</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> display_robot.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:=C5A</span></span></code></pre></div><p>目前支持以下协作机器人型号：</p><ul><li>C5A</li><li>C7A</li><li>C12A</li><li>C16A</li></ul><blockquote><p>1. 工作目录是指包含 src 和 install 文件夹的目录，例如：/home/{你的用户名}/ws 这将在 RViz 中加载指定型号机器人的 URDF 模型。</p><p>2. 更多机器人型号请访问官网查询，<a href="https://www.sh-agilebot.com" target="_blank" rel="noreferrer">https://www.sh-agilebot.com</a></p></blockquote>`,12)]))}const b=a(h,[["render",n]]);export{g as __pageData,b as default};
